// --- TAHAP 1: DI HALAMAN "MY COURSE" (Gambar 1) ---
// Cari kartu yang judulnya "Java" (jaga-jaga kalau ada course lain nanti)
// Lalu cari tombol "Start Lesson" di dalamnya
cy.contains('.card', 'Java') // Cari kotak kartu Java
.contains('Start Lesson') // Cari teks Start Lesson di dalam kotak itu
.click();
// --- TAHAP 2: DI HALAMAN PILIH LEVEL (Gambar 2) ---
// 1. Validasi URL berubah ke halaman level
// Berdasarkan screenshot inspect element gambar 1, href-nya ke /courses/level/1
cy.url({
  timeout: 20000
}).should('include', '/courses/level');
// 2. Validasi Judul Halaman muncul
cy.contains('h2', 'Start Your Lesson now').should('be.visible');
// 3. Validasi ada 3 Pilihan Level (Easy, Medium, Hard)
cy.contains('Easy').should('be.visible');
cy.contains('Medium').should('be.visible');
cy.contains('Hard').should('be.visible');
// 4. Klik tombol Start Lesson pada level "Easy"
// Trik: Cari kartu yang mengandung kata "Easy", lalu cari tombol didalamnya
// Ini penting karena ada 3 tombol "Start Lesson" di halaman ini
cy.contains('.card', 'Easy').find('a.btn-primary') // Cari elemen <a> dengan class btn-primary (tombol biru)
.should('contain', 'Start Lesson').click();
// --- TAHAP 3: VALIDASI MASUK KE DETAIL MATERI ---
// Berdasarkan inspect element Gambar 2, href Easy mengarah ke .../detail/1
cy.url({
  timeout: 30000
}).should('include', '/detail/');
// (Opsional) Pastikan tidak ada error 404/500
cy.get('body').should('not.contain', '404 Not Found');
